public class SimpleOverloading {
  public static void printNumber(int number) {
    System.out.println("Tam ədəd: " + number);
  }
  public static void printNumber(double number) {
    System.out.println("Kəsr ədəd: " + number);
  }
  public static void main(String[] args) {
    printNumber(10);
    printNumber(3.14);
  }
}
// Çıxış:
// Tam ədəd: 10
// Kəsr ədəd: 3.14

public class ParameterCountOverloading {
  public static void addNumbers(int a, int b) {
    System.out.println("İki ədədin cəmi: " + (a + b));
  }
  public static void addNumbers(int a, int b, int c) {
    System.out.println("Üç ədədin cəmi: " + (a + b + c));
  }
  public static void main(String[] args) {
    addNumbers(5, 3);
    addNumbers(5, 3, 2);
  }
}
// Çıxış:
// İki ədədin cəmi: 8
// Üç ədədin cəmi: 10

public class DifferentTypesOverloading {
  public static void display(String text) {
    System.out.println("Mətn: " + text);
  }
  public static void display(int number) {
    System.out.println("Ədəd: " + number);
  }
  public static void main(String[] args) {
    display("Salam");
    display(42);
  }
}
// Çıxış:
// Mətn: Salam
// Ədəd: 42

public class MethodSignature {
  public static void process(int number) {
    System.out.println("Tam ədəd emalı: " + number);
  }
  public static void process(String text) {
    System.out.println("Mətn emalı: " + text);
  }
  public static void main(String[] args) {
    process(100);
    process("Test");
  }
}
// Çıxış:
// Tam ədəd emalı: 100
// Mətn emalı: Test

