public class PriceFormatter {
  public static void formatPrice(int price) {
    System.out.println("Qiymət (tam ədəd): " + price + " AZN");
  }
  public static void formatPrice(double price) {
    System.out.println("Qiymət (kəsr): " + price + " AZN");
  }
  public static void main(String[] args) {
    formatPrice(50);
    formatPrice(49.99);
  }
}
